dispositivi = []
connessioni = []
servizi = []
memorizzazioni = []

def genera():
    id_disp = 0
    n = 0
    for u in utenti:
        for i in range(2):
            n = n+1
            id_disp = id_disp+1
            modello = random.choice(["cellulare", "tablet", "tv"])
            marca = random.choice(["Apple", "Samsung", "Xiaomi", "Huawei", "Panasonic"])
            inizio_conn = genera_timestamp_casuale()
            ip_conn = genera_ip()
            id_serv = n
            inizio_serv = genera_timestamp_aggiunto(inizio_conn, random.randint(10,40))
            versione = random.randint(0,499)
            nfilm = math.floor(versione / 5)
            film = films[nfilm][3]
            fine_serv = genera_timestamp_aggiunto(inizio_serv, film)
            server = random.randint(1,5)
            fine_conn = fine_serv

            dispositivi.append((id_disp, modello, marca))
            connessioni.append((time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(inizio_conn)), ip_conn, time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(fine_conn)), id_serv, id_disp, u[0]))
            servizi.append((id_serv, time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(inizio_serv)), time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(fine_serv)), versione +1 , server))
            memorizzazioni.append((server, versione + 1))

def stampa_disp():
    print("dispositivi:")
    for id, modello, marca,  in dispositivi:
        print(f'({id}, "{modello}", "{marca}"),', end="")
        if(id % 50 == 0):
            print(" ")
    print(" ")

def stampa_connessioni():
    print("connessioni:")
    n = 0
    for inizio_conn, ip_conn, fine_conn, id_serv, id_disp ,u, in connessioni:
        n = n+1
        print(f'("{inizio_conn}", {ip_conn}, "{fine_conn}", {id_serv}, {id_disp}, {u}),', end="")
        if(n % 50 == 0):
            print(" ")
    print(" ")

def stampa_servizi():
    print("servizi:")
    for id_serv, inizio_serv, fine_serv, versione, server in servizi:
        print(f'({id_serv}, "{inizio_serv}", "{fine_serv}", {versione}, {server}),', end="")
        if(id_serv % 50 == 0):
            print(" ")
    print(" ")

def stampa_memorizzazioni():
    print("memorizzazioni:")
    n = 0
    for server, versione in memorizzazioni:
        n = n+1
        prob = random.randint(0,100)
        if(prob > 95):
            print(f'({server}, {versione}, TRUE, NULL),', end="")
        else:
            print(f'({server}, {versione}, TRUE, TRUE), ', end="")
        if(n % 50 == 0):
            print(" ")
    print(" ")
        
def genera_timestamp_casuale():
    inizio_timestamp = time.mktime((2022, 1, 1, 0, 0, 0, 0, 0, 0)) 
    fine_timestamp = time.mktime((2024, 2, 1, 0, 0, 0, 0, 0, 0))  
    timestamp_casuale = random.randint(inizio_timestamp, fine_timestamp)
    return timestamp_casuale

def genera_timestamp_aggiunto(timestamp, minuti):
    secondi_aggiunti = minuti * 60  
    nuovo_timestamp = timestamp + secondi_aggiunti
    return nuovo_timestamp

def genera_ip():
    n1 = random.randint(1,100)
    n2 = random.randint(0,255)
    n3 = random.randint(0,255)
    n4 = random.randint(0,255)
    n1f = str(n1).zfill(3)
    n2f = str(n2).zfill(3)
    n3f = str(n3).zfill(3)
    n4f = str(n4).zfill(3)
    return n1f + n2f + n3f + n4f

if __name__ == "__main__":
    genera()
    stampa_disp()
    stampa_connessioni()
    stampa_servizi()
    stampa_memorizzazioni()